'use strict';

var obsidian = require('obsidian');

const DEFAULT_SETTINGS = {
	defaultFolder: '',
	colorYellow: 'highlight',
	colorAqua: 'important',
	colorPink: 'question',
	colorOrange: 'attention',
	colorBlue: 'info',
	colorGreen: 'success'
};

class KindleTransformationPlugin extends obsidian.Plugin {
	async onload() {
		await this.loadSettings();

		// 【这里把 'wand' 改成了 'book-open'】📖
		this.addRibbonIcon('book-open', 'Kindle Transformation', () => {
			this.openFilePicker();
		});

		this.addCommand({
			id: 'run-kindle-transformation',
			name: 'Run Kindle Transformation',
			callback: () => {
				this.openFilePicker();
			}
		});

		this.addSettingTab(new KindleTransformationSettingTab(this.app, this));
	}

	async loadSettings() {
		this.settings = Object.assign({}, DEFAULT_SETTINGS, await this.loadData());
	}

	async saveSettings() {
		await this.saveData(this.settings);
	}

	openFilePicker() {
		new TransformationModal(this.app, async (fileContent, fileName) => {
			const markdown = this.parseKindleHTML(fileContent);
			
			try {
				const baseName = fileName.replace('.html', '');
				const newFileName = `${baseName}.md`;
				
				let folderPath = this.settings.defaultFolder.trim();
				let finalPath = '';
				
				if (folderPath === '' || folderPath === '/') {
					finalPath = newFileName;
				} else {
					if (folderPath.startsWith('/')) folderPath = folderPath.substring(1);
					if (folderPath.endsWith('/')) folderPath = folderPath.substring(0, folderPath.length - 1);
					
					finalPath = obsidian.normalizePath(folderPath + '/' + newFileName);
					
					const folderExists = this.app.vault.getAbstractFileByPath(folderPath);
					if (!folderExists) {
						await this.app.vault.createFolder(folderPath);
					}
				}
				
				await this.app.vault.create(finalPath, markdown);
				new obsidian.Notice(`✨ Successfully transformed: ${finalPath}`);
			} catch (e) {
				new obsidian.Notice(`⚠️ Transformation failed: File might already exist.`);
				console.error(e);
			}
		}).open();
	}

	parseKindleHTML(htmlString) {
		const parser = new DOMParser();
		const doc = parser.parseFromString(htmlString, 'text/html');

		const title = doc.querySelector('.bookTitle')?.textContent?.trim() || "Unknown Title";
		const author = doc.querySelector('.authors')?.textContent?.trim() || "Unknown Author";
		let highlightCount = 0;
		
		let markdown = "";
		const elements = doc.querySelectorAll('.sectionHeading, .noteHeading, .noteText');
		
		const colorMap = {
			'yellow': this.settings.colorYellow || 'quote',
			'aqua': this.settings.colorAqua || 'quote',
			'pink': this.settings.colorPink || 'quote',
			'orange': this.settings.colorOrange || 'quote',
			'blue': this.settings.colorBlue || 'quote',
			'green': this.settings.colorGreen || 'quote'
		};

		let i = 0;
		while (i < elements.length) {
			const el = elements[i];
			if (el.classList.contains('sectionHeading')) {
				markdown = markdown.trimEnd();
				if (markdown !== "") {
					markdown += `\n\n`; 
				}
				markdown += `## ${el.textContent?.trim()}\n\n`;
				i++;
			} else if (el.classList.contains('noteHeading')) {
				const headingText = el.textContent?.trim() || "";
				if (headingText.startsWith('Highlight')) {
					highlightCount++;
					const colorSpan = el.querySelector('span[class^="highlight_"]');
					const rawColor = colorSpan ? colorSpan.textContent?.trim().toLowerCase() : 'default';
					
					const calloutType = colorMap[rawColor] || 'quote';
					
					const nextEl = elements[i + 1];
					if (nextEl && nextEl.classList.contains('noteText')) {
						const textContent = nextEl.textContent?.trim();
						markdown += `> [!${calloutType}]\n> > ${textContent}\n\n`;
						i += 2;
					} else {
						i++;
					}
				} else if (headingText.startsWith('Note')) {
					const nextEl = elements[i + 1];
					if (nextEl && nextEl.classList.contains('noteText')) {
						const noteText = nextEl.textContent?.trim();
						markdown = markdown.trimEnd();
						markdown += `\n>\n> ✏️ **Note:** ${noteText}\n\n`;
						i += 2;
					} else {
						i++;
					}
				} else {
					i++;
				}
			} else {
				i++;
			}
		}

		const frontmatter = `---\ntitle: "${title}"\nauthor: "${author}"\nhighlights: ${highlightCount}\n---\n\n`;
		return frontmatter + markdown.trimEnd() + "\n";
	}
}

class TransformationModal extends obsidian.Modal {
	constructor(app, callback) {
		super(app);
		this.callback = callback;
		this.selectedFile = null;
	}

	onOpen() {
		const { contentEl } = this;
		contentEl.empty();
		
		const container = contentEl.createDiv({
			attr: { style: 'display: flex; flex-direction: column; align-items: center; padding: 10px; gap: 24px;' }
		});

		container.createEl("h2", { 
			text: "Kindle Transformation",
			attr: { style: 'margin: 0; font-weight: 600; letter-spacing: -0.5px; color: var(--text-normal);' }
		});

		const uploadBox = container.createEl('label', {
			attr: { 
				style: 'display: flex; flex-direction: column; align-items: center; justify-content: center; width: 100%; height: 140px; border: 2px dashed var(--background-modifier-border); border-radius: 12px; cursor: pointer; transition: all 0.2s ease; background-color: var(--background-primary-alt);' 
			}
		});

		const icon = uploadBox.createSpan({ text: '📖', attr: { style: 'font-size: 36px; margin-bottom: 12px; opacity: 0.8; transition: transform 0.2s ease;' } });
		const labelText = uploadBox.createSpan({ 
			text: 'Click or Drag HTML file here', 
			attr: { style: 'color: var(--text-muted); font-size: 14px; font-weight: 500;' } 
		});

		const input = uploadBox.createEl("input", {
			type: "file",
			attr: { accept: ".html", style: 'display: none;' }
		});

		const handleFile = (file) => {
			if (file && file.name.endsWith('.html')) {
				this.selectedFile = file;
				icon.innerText = '✨';
				icon.style.transform = 'scale(1.1)';
				labelText.innerText = `Selected: ${file.name}`;
				labelText.style.color = 'var(--interactive-accent)';
				uploadBox.style.borderColor = 'var(--interactive-accent)';
				uploadBox.style.backgroundColor = 'var(--background-primary-alt)';
			} else {
				new obsidian.Notice("Please select a valid HTML file.");
				uploadBox.style.borderColor = 'var(--text-error)';
			}
		};

		input.onchange = () => {
			if (input.files?.length > 0) handleFile(input.files[0]);
		};

		uploadBox.ondragover = (e) => {
			e.preventDefault();
			uploadBox.style.borderColor = 'var(--interactive-accent)';
			uploadBox.style.backgroundColor = 'var(--background-secondary)';
			icon.style.transform = 'scale(1.1)';
		};

		uploadBox.ondragleave = (e) => {
			e.preventDefault();
			if (!this.selectedFile) {
				uploadBox.style.borderColor = 'var(--background-modifier-border)';
			}
			uploadBox.style.backgroundColor = 'var(--background-primary-alt)';
			icon.style.transform = 'scale(1)';
		};

		uploadBox.ondrop = (e) => {
			e.preventDefault();
			if (e.dataTransfer?.files?.length > 0) {
				handleFile(e.dataTransfer.files[0]);
			}
		};

		const btn = container.createEl("button", { 
			text: "Start Transformation",
			attr: { style: 'width: 100%; padding: 12px; border-radius: 8px; background-color: var(--interactive-accent); color: var(--text-on-accent); font-weight: 600; font-size: 15px; border: none; cursor: pointer; transition: opacity 0.2s ease;' }
		});
		
		btn.onmouseover = () => btn.style.opacity = '0.9';
		btn.onmouseout = () => btn.style.opacity = '1';

		btn.onclick = () => {
			const file = this.selectedFile;
			if (file) {
				const reader = new FileReader();
				reader.onload = (e) => {
					const content = e.target?.result;
					this.callback(content, file.name);
					this.close();
				};
				reader.readAsText(file);
			} else {
				new obsidian.Notice("Please select or drop an HTML file first.");
			}
		};
	}

	onClose() {
		const { contentEl } = this;
		contentEl.empty();
	}
}

class KindleTransformationSettingTab extends obsidian.PluginSettingTab {
	constructor(app, plugin) {
		super(app, plugin);
		this.plugin = plugin;
	}

	display() {
		const { containerEl } = this;
		containerEl.empty();

		new obsidian.Setting(containerEl)
			.setName('Save Folder')
			.setDesc('Specify the folder to save your notes (e.g., Kindle/Notes). Leave blank to save in the root directory.')
			.addText(text => text
				.setPlaceholder('Enter path...')
				.setValue(this.plugin.settings.defaultFolder)
				.onChange(async (value) => {
					this.plugin.settings.defaultFolder = value;
					await this.plugin.saveSettings();
				}));

		containerEl.createEl('h3', { text: 'Callout Color Mapping', attr: {style: 'margin-top: 2em;'} });
		containerEl.createEl('p', { 
			text: 'Define the Obsidian Callout type for each Kindle highlight color (e.g., quote, info, todo, tip, success, question, warning, danger, bug).', 
			attr: {style: 'color: var(--text-muted); font-size: 13px; margin-bottom: 1em;'} 
		});

		const colors = ['Yellow', 'Aqua', 'Pink', 'Orange', 'Blue', 'Green'];
		colors.forEach(color => {
			new obsidian.Setting(containerEl)
				.setName(`${color} Highlight`)
				.addText(text => text
					.setPlaceholder('Callout type')
					.setValue(this.plugin.settings[`color${color}`])
					.onChange(async (value) => {
						this.plugin.settings[`color${color}`] = value;
						await this.plugin.saveSettings();
					}));
		});

		const creditDiv = containerEl.createDiv({
			attr: { style: 'margin-top: 40px; padding-top: 20px; border-top: 1px solid var(--background-modifier-border); color: var(--text-muted); font-size: 12px; text-align: center;' }
		});
		creditDiv.innerHTML = 'Inspired by and upgraded from <a href="https://github.com/l2xu/kindle_html_importer" target="_blank" style="color: var(--text-accent);">l2xu/kindle_html_importer</a>.<br>Special thanks to the original author!';
	}
}

module.exports = KindleTransformationPlugin;
